-- Подробные пошаговые инструкции для новичков в курсе React (CodeSandbox)
-- Урок 1: Что такое React
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'React — самый популярный инструмент для создания сайтов. В этом уроке мы НИЧЕГО не устанавливаем: всё делаем прямо в браузере. Просто повторяй шаги один за другим — если знаешь JavaScript хоть немного, всё получится.',
steps = '[
  {"title": "Шаг 1. Открой готовую среду для React", "text": "Открой новую вкладку в браузере, в адресной строке набери react.new и нажми Enter. Это сайт CodeSandbox — он сам создаст готовый React-проект. Подожди 5-10 секунд, пока всё загрузится."},
  {"title": "Шаг 2. Разберись, где что находится", "text": "Экран разделён на 3 части. СЛЕВА — список файлов проекта. ПО ЦЕНТРУ — редактор кода (здесь мы пишем). СПРАВА — предпросмотр, живой результат твоего сайта. Пока просто посмотри на них."},
  {"title": "Шаг 3. Открой главный файл", "text": "В левой колонке с файлами найди файл App.js (или App.tsx) и кликни по нему один раз. В центре откроется его код. Именно этот файл рисует то, что ты видишь справа."},
  {"title": "Шаг 4. Найди главную функцию", "text": "В коде найди строку, которая начинается со слов export default function App() {. Это главный компонент — сердце приложения. Всё, что между return ( и ) — это то, что показывается на экране справа."},
  {"title": "Шаг 5. Поменяй текст на свой", "text": "Внутри return найди строку с текстом, например <h1>Hello CodeSandbox</h1>. Сотри слова Hello CodeSandbox и впиши своё, например: Привет, меня зовут Алекс!. Не трогай значки < > — только текст между ними."},
  {"title": "Шаг 6. Убедись, что всё работает", "text": "Ничего сохранять не нужно — посмотри направо. Твой новый текст уже появился в предпросмотре. Поздравляю: ты только что изменил настоящее React-приложение!"}
]'
WHERE course_id = 'react' AND position = 1;

-- Урок 2: JSX
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'JSX — это когда HTML пишут прямо внутри JavaScript. Выглядит непривычно, но именно так работает весь React. Продолжаем в том же проекте на react.new — открой его заново, если закрыл.',
steps = '[
  {"title": "Шаг 1. Открой проект и файл App", "text": "Зайди на react.new (или открой свою прошлую вкладку). Слева кликни на файл App.js, чтобы увидеть его код в центре."},
  {"title": "Шаг 2. Очисти лишнее", "text": "Внутри return ( ... ) удали всё, что там есть, оставив только пустые круглые скобки после return. Мы напишем содержимое с нуля."},
  {"title": "Шаг 3. Напиши свой первый JSX", "text": "Сразу после return ( впиши: <h1>Привет, React!</h1>. Посмотри направо — заголовок появился. Это и есть JSX: HTML прямо в коде."},
  {"title": "Шаг 4. Добавь несколько тегов в один блок", "text": "В JSX можно вернуть только ОДИН элемент. Поэтому оберни всё в <div>: напиши <div><h1>Заголовок</h1><p>Первый абзац текста</p></div>. Теперь на экране заголовок и абзац."},
  {"title": "Шаг 5. Вставь значение из JavaScript", "text": "Перед строкой return напиши: const name = \"Алекс\";. Затем внутри JSX напиши <h1>Привет, {name}</h1>. Фигурные скобки { } вставляют значение переменной прямо в разметку."},
  {"title": "Шаг 6. Проверь результат", "text": "Справа должно быть написано: Привет, Алекс. Попробуй поменять \"Алекс\" на своё имя — текст обновится мгновенно."}
]'
WHERE course_id = 'react' AND position = 2;

-- Урок 3: Компоненты
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Компонент — это переиспользуемый блок сайта: кнопка, карточка, меню. Создал один раз — вставляешь сколько угодно. Это главная идея React. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new и слева кликни файл App.js. Убери из return всё лишнее, оставим чистый лист для практики."},
  {"title": "Шаг 2. Создай свой компонент", "text": "Над функцией App (выше по коду) напиши новую функцию: function Welcome() { return <h2>Добро пожаловать!</h2>; }. Это твой собственный компонент. Важно: имя компонента ВСЕГДА с большой буквы — Welcome, а не welcome."},
  {"title": "Шаг 3. Вставь компонент в приложение", "text": "Теперь внутри return у функции App напиши: <div><Welcome /></div>. Обрати внимание на закрывающий слэш: <Welcome />. Справа появится текст Добро пожаловать!."},
  {"title": "Шаг 4. Используй компонент несколько раз", "text": "Добавь ещё две строки: <Welcome /><Welcome />. Теперь их три подряд. Один блок — используешь сколько нужно. В этом вся сила компонентов."},
  {"title": "Шаг 5. Пойми, что произошло", "text": "Ты создал кубик (Welcome) и собрал из него страницу, как из LEGO. Реальные сайты собираются из десятков таких компонентов."}
]'
WHERE course_id = 'react' AND position = 3;

-- Урок 4: Props
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Props — это способ передать данные в компонент, чтобы один и тот же блок показывал РАЗНОЕ. Например, карточка товара с разными названиями. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js на react.new", "text": "Зайди на react.new, слева кликни App.js."},
  {"title": "Шаг 2. Создай компонент, принимающий props", "text": "Над функцией App напиши: function Hello(props) { return <h2>Привет, {props.name}!</h2>; }. Слово props — это коробка с данными, которые придут снаружи."},
  {"title": "Шаг 3. Передай данные при использовании", "text": "Внутри return функции App напиши: <div><Hello name=\"Аня\" /><Hello name=\"Борис\" /></div>. Мы передали разные имена через name=..."},
  {"title": "Шаг 4. Посмотри результат", "text": "Справа появятся две строки: Привет, Аня! и Привет, Борис!. Один компонент — разные данные. Это и есть props."},
  {"title": "Шаг 5. Добавь второй prop", "text": "Поменяй компонент на function Hello(props) { return <h2>{props.name}, тебе {props.age} лет</h2>; }, а при вызове напиши <Hello name=\"Аня\" age=\"20\" />. Теперь передаётся два значения."}
]'
WHERE course_id = 'react' AND position = 4;

-- Урок 5: useState
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'useState — это память компонента. Когда данные в ней меняются, React сам перерисовывает экран. Сделаем счётчик, который увеличивается по кнопке. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, слева кликни App.js."},
  {"title": "Шаг 2. Подключи useState", "text": "В самом верху файла добавь строку: import { useState } from \"react\";. Это включает механизм памяти."},
  {"title": "Шаг 3. Создай переменную состояния", "text": "Внутри функции App, ПЕРЕД return, напиши: const [count, setCount] = useState(0);. Здесь count — текущее число (начинается с 0), а setCount — функция, чтобы его менять."},
  {"title": "Шаг 4. Покажи число и добавь кнопку", "text": "Внутри return напиши: <div><h1>Счётчик: {count}</h1><button onClick={() => setCount(count + 1)}>Плюс один</button></div>."},
  {"title": "Шаг 5. Нажми кнопку в предпросмотре", "text": "Справа появилась кнопка Плюс один. Нажми на неё несколько раз — число растёт! React сам обновляет экран, когда меняется состояние. Ты этого не программировал — оно работает само."}
]'
WHERE course_id = 'react' AND position = 5;

-- Урок 6: События
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'События — это реакция на действия пользователя: клик, наведение, ввод. Научимся ловить клик по кнопке и показывать сообщение. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, кликни слева App.js."},
  {"title": "Шаг 2. Создай функцию-обработчик", "text": "Внутри функции App, перед return, напиши: function handleClick() { alert(\"Ты нажал на кнопку!\"); }. Это действие, которое сработает по клику."},
  {"title": "Шаг 3. Привяжи её к кнопке", "text": "Внутри return напиши: <button onClick={handleClick}>Нажми меня</button>. Слово onClick означает при клике. Важно: пишем handleClick без скобок."},
  {"title": "Шаг 4. Проверь", "text": "Справа появилась кнопка. Нажми — выскочит окошко с текстом. Ты обработал событие!"},
  {"title": "Шаг 5. Другие события", "text": "Кроме onClick есть onMouseOver (наведение мыши) и onChange (изменение поля ввода). Попробуй заменить onClick на onMouseOver и наведи мышку на кнопку."}
]'
WHERE course_id = 'react' AND position = 6;

-- Урок 7: Списки и map
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Меню, список товаров, посты — это всё списки. React рисует их через метод map. Это ключевой приём, который встречается в каждом проекте. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, кликни слева App.js."},
  {"title": "Шаг 2. Создай массив данных", "text": "Внутри функции App, перед return, напиши: const fruits = [\"Яблоко\", \"Банан\", \"Апельсин\"];. Это список из трёх строк."},
  {"title": "Шаг 3. Преврати массив в список на экране", "text": "Внутри return напиши: <ul>{fruits.map((fruit) => <li key={fruit}>{fruit}</li>)}</ul>. Метод map берёт каждый элемент и делает из него строчку списка <li>."},
  {"title": "Шаг 4. Разберись, что такое key", "text": "Ты заметил key={fruit}. React просит уникальную метку для каждого элемента списка, чтобы правильно их обновлять. Без key будет предупреждение."},
  {"title": "Шаг 5. Проверь и дополни", "text": "Справа появился маркированный список из трёх фруктов. Добавь в массив ещё один фрукт через запятую — он сразу появится на экране."}
]'
WHERE course_id = 'react' AND position = 7;

-- Урок 8: Условный рендеринг
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Иногда блок нужно показать только при условии: например, кнопку Выйти — только когда пользователь вошёл. React делает это элегантно. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, кликни слева App.js. Вверху добавь import { useState } from \"react\";."},
  {"title": "Шаг 2. Создай состояние да/нет", "text": "Внутри App, перед return, напиши: const [isLoggedIn, setIsLoggedIn] = useState(false);. Значение false означает пользователь не вошёл."},
  {"title": "Шаг 3. Покажи блок по условию", "text": "Внутри return напиши: <div>{isLoggedIn ? <h1>Привет!</h1> : <h1>Войдите, пожалуйста</h1>}</div>. Читается так: ЕСЛИ isLoggedIn — показать Привет, ИНАЧЕ — Войдите."},
  {"title": "Шаг 4. Добавь кнопку-переключатель", "text": "После этого блока добавь: <button onClick={() => setIsLoggedIn(!isLoggedIn)}>Переключить</button>. Значок ! меняет true на false и обратно."},
  {"title": "Шаг 5. Проверь", "text": "Нажимай кнопку Переключить справа — текст будет меняться между Войдите и Привет. Это условный рендеринг в действии."}
]'
WHERE course_id = 'react' AND position = 8;

-- Урок 9: Формы
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Формы — это как сайт собирает данные от человека: имя, email, сообщение. Свяжем поле ввода с состоянием и покажем, что печатает пользователь. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, кликни слева App.js. Вверху добавь import { useState } from \"react\";."},
  {"title": "Шаг 2. Создай состояние для текста", "text": "Внутри App, перед return, напиши: const [text, setText] = useState(\"\");. Пустые кавычки — поле пока пустое."},
  {"title": "Шаг 3. Добавь поле ввода", "text": "Внутри return напиши: <input value={text} onChange={(e) => setText(e.target.value)} />. Здесь onChange срабатывает на каждую букву, а e.target.value — это то, что напечатал пользователь."},
  {"title": "Шаг 4. Покажи введённое рядом", "text": "После input добавь: <p>Ты ввёл: {text}</p>. Теперь под полем будет отображаться текст."},
  {"title": "Шаг 5. Проверь", "text": "Справа кликни в поле ввода и печатай — текст мгновенно появляется в строке ниже. Поле и состояние связаны."}
]'
WHERE course_id = 'react' AND position = 9;

-- Урок 10: useEffect
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'useEffect запускает твой код в нужный момент: когда компонент появился на экране или когда изменились данные. Например, чтобы загрузить информацию при открытии. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой App.js", "text": "Зайди на react.new, кликни слева App.js. Вверху напиши import { useState, useEffect } from \"react\";."},
  {"title": "Шаг 2. Добавь состояние", "text": "Внутри App, перед return, напиши: const [count, setCount] = useState(0);."},
  {"title": "Шаг 3. Добавь эффект", "text": "Ниже напиши: useEffect(() => { document.title = \"Кликов: \" + count; }, [count]);. Этот код меняет заголовок вкладки браузера каждый раз, когда меняется count."},
  {"title": "Шаг 4. Добавь кнопку", "text": "Внутри return напиши: <button onClick={() => setCount(count + 1)}>Клик</button>."},
  {"title": "Шаг 5. Проверь заголовок вкладки", "text": "Нажимай кнопку и смотри на НАЗВАНИЕ вкладки браузера (сверху) — там будет меняться число кликов. Квадратные скобки [count] означают: запускай эффект только при изменении count."}
]'
WHERE course_id = 'react' AND position = 10;

-- Урок 11: Стилизация
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Разберём, как раскрашивать React-компоненты. Покажу два простых способа: через готовый CSS-файл и через стили прямо в коде. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой проект", "text": "Зайди на react.new. Слева ты увидишь файлы App.js и styles.css (или App.css)."},
  {"title": "Шаг 2. Способ 1 — через className", "text": "В App.js внутри return напиши: <h1 className=\"title\">Заголовок</h1>. В React класс называется className, а не class."},
  {"title": "Шаг 3. Добавь стиль в CSS-файл", "text": "Слева кликни файл styles.css. В самый низ добавь: .title { color: red; font-size: 40px; }. Справа заголовок станет красным и крупным."},
  {"title": "Шаг 4. Способ 2 — стиль прямо в коде", "text": "Вернись в App.js. Добавь: <p style={{ color: \"blue\", background: \"yellow\" }}>Текст</p>. Обрати внимание на ДВОЙНЫЕ фигурные скобки — это обязательно."},
  {"title": "Шаг 5. Сравни способы", "text": "className с CSS-файлом удобен для больших проектов, а style={{}} — для быстрых точечных правок. Попробуй поменять цвета на свои."}
]'
WHERE course_id = 'react' AND position = 11;

-- Урок 12: Финальный проект
UPDATE t_p80207328_code_school_online.lessons SET
intro = 'Финальный проект — настоящее приложение Список задач! Соберём вместе всё: состояние, поле ввода, событие и список через map. Не спеши, повторяй шаги по порядку. Работаем на react.new.',
steps = '[
  {"title": "Шаг 1. Открой чистый App.js", "text": "Зайди на react.new, кликни App.js. Вверху напиши: import { useState } from \"react\";. Внутри return пока оставь пустой <div></div>."},
  {"title": "Шаг 2. Заведи два состояния", "text": "Перед return напиши две строки: const [task, setTask] = useState(\"\"); — текст в поле, и const [tasks, setTasks] = useState([]); — список всех задач (пока пустой)."},
  {"title": "Шаг 3. Сделай функцию добавления", "text": "Ниже напиши: function addTask() { setTasks([...tasks, task]); setTask(\"\"); }. Она добавляет текущую задачу в список и очищает поле. Три точки ... копируют старые задачи и дописывают новую."},
  {"title": "Шаг 4. Добавь поле и кнопку", "text": "Внутри <div> напиши: <input value={task} onChange={(e) => setTask(e.target.value)} /> и рядом <button onClick={addTask}>Добавить</button>."},
  {"title": "Шаг 5. Выведи список задач", "text": "После кнопки, внутри того же <div>, добавь: <ul>{tasks.map((t, i) => <li key={i}>{t}</li>)}</ul>. Метод map рисует каждую задачу строкой списка."},
  {"title": "Шаг 6. Проверь своё приложение", "text": "Справа напечатай задачу, нажми Добавить — она появится в списке. Добавь ещё несколько. Поздравляю, ты собрал первое настоящее React-приложение с нуля! 🎉"}
]'
WHERE course_id = 'react' AND position = 12;